import anthropic
import json

client = anthropic.Anthropic()

# Define tools the model can invoke
tools = [
    {
        "name": "calculator",
        "description": "Evaluates a Python arithmetic expression and returns the result.",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {"type": "string", "description": "e.g. '(12 * 3.14159) ** 2'"}
            },
            "required": ["expression"],
        },
    },
    {
        "name": "web_search",
        "description": "Searches the web and returns the top results.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
]


def run_tool(name: str, inputs: dict) -> str:
    """Stub that would dispatch to real tool implementations."""
    if name == "calculator":
        result = eval(inputs["expression"], {"__builtins__": {}})   # safe eval in practice
        return str(result)
    if name == "web_search":
        return f"[Search results for '{inputs['query']}' would appear here]"
    return "Unknown tool"


def agentic_loop(user_message: str) -> str:
    """
    Run the model in a loop: generate -> execute tool calls -> feed results back.
    Stops when the model produces a text-only response (no tool calls).
    """
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            # Final text answer
            return next(b.text for b in response.content if b.type == "text")

        # Execute all tool calls in this turn
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = run_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        # Append model response and tool results, then continue
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})


answer = agentic_loop("What is 15% of 847, and what is the population of Tokyo?")
print(answer)
